<template><div><div class="flex justify-between"><h3 class="font-bold">Upcoming Reservations</h3><div><button @click="t='checkin'" :class="cls('checkin')">Check In</button><button @click="t='checkout'" :class="cls('checkout')">Check Out</button></div></div><table class="w-full text-sm mt-3"><thead><tr class="text-left"><th>Time</th><th>Guest</th><th>Date</th><th>Room</th><th></th></tr></thead><tbody><tr v-for="r in filtered" :key="r.id" class="border-t"><td>{{r.check_in}}</td><td>{{r.guest?.name}}</td><td>{{r.check_out}}</td><td>{{r.room?.number}}</td><td><button class="bg-emerald-500 text-white px-2 rounded">Registration</button></td></tr></tbody></table></div></template>
<script setup>import { computed, ref } from 'vue'; const props=defineProps({rows:Array}); const t=ref('checkin'); const filtered=computed(()=>props.rows?.filter(r=>r.stay_type===t.value).slice(0,6)||[]); const cls=v=>`px-3 py-1 rounded-full ${t.value===v?'bg-rose-500 text-white':'bg-slate-200'}`;</script>
